using Microsoft.EntityFrameworkCore;
using System.Threading.Tasks;

public class EventBookingContext : DbContext
{
    public DbSet<Event> Events { get; set; }
    public DbSet<Ticket> Tickets { get; set; }

    protected override void OnConfiguring(DbContextOptionsBuilder optionsBuilder)
        => optionsBuilder.UseSqlServer(@"Data Source=(localdb)\mssqllocaldb;Initial Catalog=EventBookingDb;Integrated Security=True");

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Ticket>()
            .HasOne(t => t.Event)
            .WithMany(e => e.Tickets)
            .HasForeignKey(t => t.EventId);
    }
}

public class Event
{
    public int Id { get; set; }
    public string Name { get; set; }
    public int AvailableSeats { get; set; }
    public ICollection<Ticket> Tickets { get; set; }
}

public class Ticket
{
    public int Id { get; set; }
    public Event Event { get; set; }
    public int EventId { get; set; }
    public bool IsPurchased { get; set; } = false;
}

public class EventBookingService
{
    private readonly EventBookingContext _context;

    public EventBookingService(EventBookingContext context)
        => _context = context;

    public async Task PurchaseTicketsAsync(int eventId, int quantity)
    {
        var eventEntity = await _context.Events.FindAsync(eventId);
        if (eventEntity == null || eventEntity.AvailableSeats < quantity)
            throw new InvalidOperationException("Event not found or insufficient seats available");

        using var transaction = _context.Database.BeginTransaction();
        try
        {
            // Check-then-act sequence: update inventory before marking tickets as purchased
            for (int i = 0; i < quantity; i++)
            {
                var ticketEntity = new Ticket { EventId = eventId, IsPurchased = true };
                _context.Tickets.Add(ticketEntity);
            }

            await _context.SaveChangesAsync();

            // Update event's available seats after successful purchase
            eventEntity.AvailableSeats -= quantity;
            _context.Events.Update(eventEntity);

            await _context.SaveChangesAsync();
            transaction.Commit();
        }
        catch (Exception ex)
        {
            transaction.Rollback();
            throw new InvalidOperationException("Failed to process ticket purchase", ex);
        }
    }
